const item = $input.first();
const binaryData = item.binary || {};
const binaryKeys = Object.keys(binaryData);

if (binaryKeys.length === 0) {
  return [{ json: { ...item.json, cv_valid: false, error_code: 'NO_FILE', error_message: 'Моля качете CV файл в PDF формат.' } }];
}

const pdfField = binaryKeys.find(k => {
  const b = binaryData[k];
  return b.fileType === 'pdf' || (b.mimeType && b.mimeType.toLowerCase().includes('pdf'));
});

if (!pdfField) {
  const got = binaryData[binaryKeys[0]];
  const gotType = got.fileExtension || got.mimeType || 'неизвестен';
  return [{
    json: { ...item.json, cv_valid: false, error_code: 'WRONG_FORMAT', error_message: `Само PDF файлове се поддържат. Получен формат: ${gotType}.` },
    binary: binaryData
  }];
}

return [{
  json: { ...item.json, cv_valid: true, binary_field: pdfField },
  binary: binaryData
}];

const cvProfile = $input.first().json.output;
const prefs = $('Normalize Input').first().json;

const urlMap = {
  'Backend':  'https://dev.bg/company/jobs/back-end-development/',
  'Frontend': 'https://dev.bg/company/jobs/front-end-development/',
  'Fullstack':'https://dev.bg/company/jobs/full-stack-development/',
  'QA':       'https://dev.bg/company/jobs/quality-assurance/',
  'Mobile':   'https://dev.bg/company/jobs/mobile/',
  'DevOps':   'https://dev.bg/company/jobs/infrastructure/',
  'Data':     'https://dev.bg/company/jobs/data-science-and-analytics/'
};

const locationMap = {
  'Remote':       'remote',
  'София':       'sofiya',
  'Пловдив':      'plovdiv',
  'Варна':        'varna',
  'Бургас':       'burgas',
  'Русе':         'ruse',
  'Стара Загора': 'stara-zagora'
};

const jobType = cvProfile?.job_type || 'Backend';
const baseUrl = urlMap[jobType] || 'https://dev.bg/company/jobs/';
const locationSlug = locationMap[prefs.location];
const scrapeUrl = locationSlug
  ? baseUrl + '?_job_location=' + encodeURIComponent(locationSlug)
  : baseUrl;

return [{
  json: {
    cv_profile: {
      skills:               cvProfile?.skills || [],
      programming_languages: cvProfile?.programming_languages || [],
      frameworks:            cvProfile?.frameworks || [],
      tools:                 cvProfile?.tools || [],
      spoken_languages:      cvProfile?.spoken_languages || [],
      experience_level:      cvProfile?.experience_level || 'Mid',
      job_type:              jobType,
      years_of_experience:   cvProfile?.years_of_experience || 0,
      job_titles:            cvProfile?.job_titles || []
    },
    scrape_url:      scrapeUrl,
    location:        prefs.location,
    language:        prefs.language,
    user_email:      prefs.user_email,
    days_back:       prefs.days_back || 5
  }
}];

const item = $input.first();
const jobs = (item.json.output?.jobs || []);

// Get job-specific links from Firecrawl (jobads URLs are individual job pages)
const allLinks = $('Scrape dev.bg via Firecrawl').first().json.data?.links || [];
const jobLinks = allLinks.filter(l =>
  typeof l === 'string' && l.includes('dev.bg/company/jobads/')
);

// Assign URL by page order — links appear in the same order as job cards
const jobsWithUrls = jobs.map((job, i) => ({
  ...job,
  url: jobLinks[i] || ''
}));

return [{ json: { output: { jobs: jobsWithUrls } } }];

// Index-match scored items with original job data (Information Extractor discards original fields)
const scoreItems = $input.all();
const originalItems = $('Compose Scoring Input').all();

return scoreItems.map((scoreItem, i) => {
  const scoreData = scoreItem.json.output || {};
  const jobData = (originalItems[i] || { json: {} }).json;

  return {
    json: {
      title: jobData.title || '',
      company: jobData.company || '',
      url: jobData.url || '',
      date_posted: jobData.date_posted || '',
      location: jobData.location || '',
      employment_type: jobData.employment_type || '',
      description: (jobData.description || '').substring(0, 500),
      score: typeof scoreData.score === 'number' ? scoreData.score : 0,
      matched_skills: Array.isArray(scoreData.matched_skills) ? scoreData.matched_skills : [],
      missing_skills: Array.isArray(scoreData.missing_skills) ? scoreData.missing_skills : [],
      experience_match: scoreData.experience_match === true,
      summary: scoreData.summary || ''
    }
  };
});
